tests.code:
cy.intercept('GET', '**/timetable/conflicts', {
  body: []
}).as('noMoreConflicts');
cy.visit('/');
cy.wait('@noMoreConflicts', {
  timeout: 10000
});
cy.get('body').then($body => {
  const text = $body.text();
  const conflictCleared = text.includes('0') || text.toLowerCase().includes('no conflict');
  expect(conflictCleared).to.be.true;
});
